class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        L = index
        R = n - index - 1

        def calculate_sum(m, x):
            if m == 0:
                return 0
            t = x - 1
            if m <= t:
                return m * (2 * x - m - 1) // 2
            else:
                sum_down = (x - 1) * x // 2
                sum_ones = (m - t) * 1
                return sum_down + sum_ones

        low = 1
        high = maxSum
        best = 0

        while low <= high:
            mid = (low + high) // 2
            sum_left = calculate_sum(L, mid)
            sum_right = calculate_sum(R, mid)
            total = sum_left + mid + sum_right

            if total <= maxSum:
                best = mid
                low = mid + 1
            else:
                high = mid - 1

        return best
